// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.hypergraph;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.junit.jupiter.api.Test;

class HypergraphTest {

	@Test
	void addNodeAssignsSequentialIndexes() {
		Hypergraph graph = new Hypergraph();
		assertEquals(0, graph.addNode());
		assertEquals(1, graph.addNode());
		assertEquals(2, graph.nodeCount());
		assertEquals(0b11L, graph.allNodes());
	}

	@Test
	void simpleEdgeFoldsIntoSimpleNeighborhood() {
		Hypergraph graph = new Hypergraph();
		int a = graph.addNode();
		int b = graph.addNode();
		int edge = graph.addEdge(NodeSets.bit(a), NodeSets.bit(b));
		assertEquals(0, edge);
		assertEquals(NodeSets.bit(b), graph.node(a).simpleNeighborhood);
		assertEquals(NodeSets.bit(a), graph.node(b).simpleNeighborhood);
		assertTrue(graph.node(a).complexArcs.isEmpty());
		assertTrue(graph.node(b).complexArcs.isEmpty());
	}

	@Test
	void complexEdgeIsListedOnEveryMemberNodeWithDirectedArcs() {
		Hypergraph graph = new Hypergraph();
		int a = graph.addNode();
		int b = graph.addNode();
		int c = graph.addNode();
		long left = NodeSets.bit(a) | NodeSets.bit(b);
		long right = NodeSets.bit(c);
		int edge = graph.addEdge(left, right);

		assertEquals(0L, graph.node(a).simpleNeighborhood);
		assertEquals(java.util.List.of(2 * edge), graph.node(a).complexArcs);
		assertEquals(java.util.List.of(2 * edge), graph.node(b).complexArcs);
		assertEquals(java.util.List.of(2 * edge + 1), graph.node(c).complexArcs);

		// Arc 2e is as given, arc 2e+1 is the swapped duplicate.
		assertEquals(left, graph.arc(2 * edge).left());
		assertEquals(right, graph.arc(2 * edge).right());
		assertEquals(right, graph.arc(2 * edge + 1).left());
		assertEquals(left, graph.arc(2 * edge + 1).right());
		assertEquals(left, graph.edgeLeft(edge));
		assertEquals(right, graph.edgeRight(edge));
	}

	@Test
	void edgeCountCountsUndirectedEdges() {
		Hypergraph graph = new Hypergraph();
		int a = graph.addNode();
		int b = graph.addNode();
		int c = graph.addNode();
		graph.addEdge(NodeSets.bit(a), NodeSets.bit(b));
		graph.addEdge(NodeSets.bit(b), NodeSets.bit(c));
		assertEquals(2, graph.edgeCount());
	}

	@Test
	void rejectsOverlappingSides() {
		Hypergraph graph = new Hypergraph();
		int a = graph.addNode();
		int b = graph.addNode();
		assertThrows(IllegalArgumentException.class,
				() -> graph.addEdge(NodeSets.bit(a) | NodeSets.bit(b), NodeSets.bit(b)));
	}

	@Test
	void rejectsEmptySide() {
		Hypergraph graph = new Hypergraph();
		int a = graph.addNode();
		assertThrows(IllegalArgumentException.class, () -> graph.addEdge(NodeSets.bit(a), 0L));
	}

	@Test
	void rejectsUnknownNodes() {
		Hypergraph graph = new Hypergraph();
		int a = graph.addNode();
		assertThrows(IllegalArgumentException.class, () -> graph.addEdge(NodeSets.bit(a), NodeSets.bit(5)));
	}

	@Test
	void dotRendersSimpleAndComplexEdges() {
		Hypergraph graph = new Hypergraph();
		int a = graph.addNode();
		int b = graph.addNode();
		int c = graph.addNode();
		graph.addEdge(NodeSets.bit(a), NodeSets.bit(b));
		graph.addEdge(NodeSets.bit(a) | NodeSets.bit(b), NodeSets.bit(c));
		String[] names = { "A", "B", "C" };
		String dot = graph.toDot(i -> names[i]);
		assertTrue(dot.contains("A [shape=box];"), dot);
		assertTrue(dot.contains("A -- B;"), dot);
		assertTrue(dot.contains("e1 [shape=point,label=\"{A,B}--{C}\"];"), dot);
		assertTrue(dot.contains("C -- e1;"), dot);
	}
}
